/**
 * The Void — Game Engine Tests
 *
 * Verifies core game mechanics:
 * - observer creation
 * - Movement costs HEX (the clinamen)
 * - Failure generates learning energy
 * - Stagnation drains HEX
 * - Dimension ascension via failure accumulation
 * - The Fold (Quine cycle)
 * - Balance invariants hold at every state
 * - Monte Carlo encounters are fair (long-run)
 */

import { describe, it, expect } from 'vitest';
import {
  createObserver,
  moveObserver,
  resolveEncounter,
  executeFold,
  generateTile,
  verifyBalanceInvariants,
  dimensionalFastTravel,
} from '../void-game-engine';
import { createGameCoordinate, originCoordinate } from '../void-game-coordinate';
import type { ObserverState } from '../void-game-types';
import { GNOSTIC } from '../math';

describe('void-game-engine', () => {
  // ── observer Creation ───────────────────────────────────────────

  describe('createObserver', () => {
    it('creates a observer at origin with starting HEX', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      expect(m.did).toBe('did:test:1');
      expect(m.coordinate.seed).toBe(42);
      expect(m.coordinate.dimension).toBe(0);
      expect(m.energy).toBe(100);
      expect(m.totalFailures).toBe(0);
      expect(m.totalSuccesses).toBe(0);
      expect(m.cycleCount).toBe(0);
      expect(m.sliver).toBe(0);
    });

    it('rejects identical major and minor phyle', () => {
      expect(() =>
        createObserver('did:test:1', 42, 'scientist', 'scientist', 'dps')
      ).toThrow('Major and minor phyle must differ');
    });

    it('starts with learning energy', () => {
      const m = createObserver('did:test:1', 42, 'philosopher', 'builder', 'tank');
      expect(m.wisdom).toBeGreaterThan(0);
    });

    it('passes balance invariants at creation', () => {
      const m = createObserver('did:test:1', 42, 'aesthete', 'hedonist', 'healer');
      const { valid, violations } = verifyBalanceInvariants(m);
      expect(valid).toBe(true);
      expect(violations).toHaveLength(0);
    });
  });

  // ── Movement ────────────────────────────────────────────────────

  describe('moveObserver', () => {
    it('costs at least 1 HEX (the clinamen)', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const { state } = moveObserver(m, 0);
      expect(state.energy).toBeLessThan(m.energy);
    });

    it('moves to the correct hex position', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const { state } = moveObserver(m, 0); // East
      expect(state.coordinate.hexQ).toBe(1);
      expect(state.coordinate.hexR).toBe(0);
    });

    it('emits a move event', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const { events } = moveObserver(m, 0);
      const moveEvent = events.find((e) => e.type === 'move');
      expect(moveEvent).toBeDefined();
    });

    it('reveals the tile', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const { tile } = moveObserver(m, 0);
      expect(tile.visibility).toBe('explored');
    });

    it('emits death event when HEX is depleted', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      // Drain all HEX
      const depleted: ObserverState = { ...m, energy: 0 };
      const { events } = moveObserver(depleted, 0);
      const deathEvent = events.find((e) => e.type === 'death');
      expect(deathEvent).toBeDefined();
      if (deathEvent?.type === 'death') {
        expect(deathEvent.cause).toBe('energy_depleted');
      }
    });

    it('maintains balance invariants through movement', () => {
      let state = createObserver('did:test:1', 42, 'nihilist', 'aesthete', 'fixer');
      for (let i = 0; i < 10; i++) {
        const result = moveObserver(state, i % 6);
        state = result.state;
        if (state.energy <= 0) break;
        const { valid } = verifyBalanceInvariants(state);
        expect(valid).toBe(true);
      }
    });
  });

  // ── Tile Generation ─────────────────────────────────────────────

  describe('generateTile', () => {
    it('is deterministic — same coordinate produces same tile', () => {
      const coord = createGameCoordinate(42, 3, 5, -3, 0);
      const tile1 = generateTile(coord);
      const tile2 = generateTile(coord);
      expect(tile1.feature).toBe(tile2.feature);
      expect(tile1.energy).toBe(tile2.energy);
      expect(tile1.hasEncounter).toBe(tile2.hasEncounter);
    });

    it('produces different tiles for different coordinates', () => {
      const tiles = [];
      for (let q = -5; q <= 5; q++) {
        const coord = createGameCoordinate(42, 3, q, -q, 0);
        tiles.push(generateTile(coord));
      }
      // Not all tiles should be identical (probabilistic, but very safe)
      const features = tiles.map((t) => t.feature);
      const unique = new Set(features);
      expect(unique.size).toBeGreaterThanOrEqual(1);
    });

    it('starts unexplored', () => {
      const coord = createGameCoordinate(42, 3, 1, -1, 0);
      const tile = generateTile(coord);
      expect(tile.visibility).toBe('unexplored');
    });

    it('respects cube constraint', () => {
      const coord = createGameCoordinate(42, 3, 3, -2, 0);
      const tile = generateTile(coord);
      expect(tile.q + tile.r + tile.s).toBe(0);
    });
  });

  // ── Encounter Resolution ────────────────────────────────────────

  describe('resolveEncounter', () => {
    it('costs at least 1 HEX', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const { result } = resolveEncounter(m, 5, 12345);
      expect(result.energyRadiated).toBeGreaterThanOrEqual(1);
    });

    it('failure generates more learning than success', () => {
      // Run many encounters and measure average learning from each outcome
      let totalFailureLearning = 0;
      let totalSuccessLearning = 0;
      let failureCount = 0;
      let successCount = 0;

      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');

      for (let i = 0; i < 1000; i++) {
        const { result } = resolveEncounter(m, 5, i);
        if (result.newFailure) {
          totalFailureLearning += result.learningGenerated;
          failureCount++;
        } else {
          totalSuccessLearning += result.learningGenerated;
          successCount++;
        }
      }

      // Failure MUST generate more learning per event than success
      const avgFailureLearning = failureCount > 0 ? totalFailureLearning / failureCount : 0;
      const avgSuccessLearning = successCount > 0 ? totalSuccessLearning / successCount : 0;
      expect(avgFailureLearning).toBeGreaterThan(avgSuccessLearning);
    });

    it('Monte Carlo produces both successes and failures (fairness)', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      let successes = 0;
      let failures = 0;

      for (let i = 0; i < 500; i++) {
        const { result } = resolveEncounter(m, 5, i * 31);
        if (result.newFailure) failures++;
        else successes++;
      }

      // Both outcomes must occur (fair distribution)
      expect(successes).toBeGreaterThan(0);
      expect(failures).toBeGreaterThan(0);
    });

    it('maintains balance invariants through encounters', () => {
      let state = createObserver('did:test:1', 42, 'builder', 'hedonist', 'range');
      for (let i = 0; i < 50; i++) {
        if (state.energy <= 0) break;
        const { state: newState } = resolveEncounter(state, 5, i);
        state = newState;
        const { valid } = verifyBalanceInvariants(state);
        expect(valid).toBe(true);
      }
    });
  });

  // ── Dimension Ascension ─────────────────────────────────────────

  describe('dimension ascension', () => {
    it('accumulating failures eventually triggers ascension', () => {
      let state = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      // Moderate HEX — enough to survive but not so much that failure never happens
      state = { ...state, energy: 500 };

      let ascended = false;
      for (let i = 0; i < 500; i++) {
        if (state.energy <= 0) break;
        const { state: newState, events } = resolveEncounter(state, 50, i * 7);
        state = newState;
        if (events.some((e) => e.type === 'dimension_transition')) {
          ascended = true;
          break;
        }
      }

      expect(ascended).toBe(true);
      expect(state.coordinate.dimension).toBeGreaterThan(0);
    });
  });

  // ── The Fold ────────────────────────────────────────────────────

  describe('executeFold', () => {
    it('rejects fold from non-Pleroma dimension', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      expect(() => executeFold(m)).toThrow(/Must be at Pleroma/);
    });

    it('resets to dimension 0 with incremented seed and sliver', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const atPleroma: ObserverState = {
        ...m,
        coordinate: createGameCoordinate(42, 9, 0, 0, 1000),
        totalFailures: 200,
        wisdom: 500,
      };

      const { state, events } = executeFold(atPleroma);
      expect(state.coordinate.dimension).toBe(0);
      expect(state.coordinate.seed).toBe(43); // Seed increments
      expect(state.sliver).toBe(1); // Sliver +1
      expect(state.cycleCount).toBe(1);
      expect(state.wisdom).toBe(500); // Knowledge persists

      const foldEvent = events.find((e) => e.type === 'fold');
      expect(foldEvent).toBeDefined();
    });

    it('gives starting bonus proportional to sliver', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const atPleroma: ObserverState = {
        ...m,
        coordinate: createGameCoordinate(42, 9, 0, 0, 0),
        sliver: 5,
        cycleCount: 5,
      };

      const { state } = executeFold(atPleroma);
      expect(state.energy).toBeGreaterThan(100); // More than STARTING_ENERGY
    });
  });

  // ── Balance Invariants ──────────────────────────────────────────

  describe('verifyBalanceInvariants', () => {
    it('passes for fresh observer', () => {
      const m = createObserver('did:test:1', 42, 'philosopher', 'nihilist', 'tank');
      const { valid } = verifyBalanceInvariants(m);
      expect(valid).toBe(true);
    });

    it('detects negative HEX', () => {
      const m = createObserver('did:test:1', 42, 'philosopher', 'nihilist', 'tank');
      const bad: ObserverState = { ...m, energy: -1 };
      const { valid, violations } = verifyBalanceInvariants(bad);
      expect(valid).toBe(false);
      expect(violations.some((v) => v.includes('Energy negative'))).toBe(true);
    });

    it('detects negative learning energy', () => {
      const m = createObserver('did:test:1', 42, 'philosopher', 'nihilist', 'tank');
      const bad: ObserverState = { ...m, wisdom: -1 };
      const { valid, violations } = verifyBalanceInvariants(bad);
      expect(valid).toBe(false);
      expect(violations.some((v) => v.includes('Learning energy negative'))).toBe(true);
    });
  });

  // ── Dimensional Fast Travel ──────────────────────────────────────

  describe('dimensionalFastTravel', () => {
    it('rejects travel to uncompleted dimensions', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      expect(() => dimensionalFastTravel(m, 3)).toThrow(/Cannot fast-travel/);
    });

    it('allows travel to completed (lower) dimensions', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const atDim5: ObserverState = {
        ...m,
        coordinate: createGameCoordinate(42, 5, 10, -5, 100),
        highestDimension: 5,
        energy: 500,
      };

      const { state, events } = dimensionalFastTravel(atDim5, 3);
      expect(state.coordinate.dimension).toBe(3);
      const transition = events.find((e) => e.type === 'dimension_transition');
      expect(transition).toBeDefined();
    });

    it('scales spatial position by β₁ ratio (Nether-style compression)', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      // Dim 8 (β₁=21) at hex (21, -21, 0)
      const atVoid: ObserverState = {
        ...m,
        coordinate: createGameCoordinate(42, 8, 21, -21, 100),
        highestDimension: 8,
        energy: 500,
      };

      // Travel to dim 3 (β₁=3). Scale = 21/3 = 7x
      const { state } = dimensionalFastTravel(atVoid, 3);
      expect(state.coordinate.hexQ).toBe(Math.round(21 * 7)); // 147
      expect(state.coordinate.hexR).toBe(Math.round(-21 * 7)); // -147
    });

    it('costs 1 HEX per dimension traversed', () => {
      const m = createObserver('did:test:1', 42, 'scientist', 'mystic', 'dps');
      const atDim5: ObserverState = {
        ...m,
        coordinate: createGameCoordinate(42, 5, 0, 0, 0),
        highestDimension: 5,
        energy: 100,
      };

      // Travel 5→3 = 2 dimensions = 2 HEX
      const { state } = dimensionalFastTravel(atDim5, 3);
      expect(state.energy).toBe(98);
    });
  });

  // ── Phyle/Archetype Balance ─────────────────────────────────────

  describe('phyle × particleType balance', () => {
    it('no phyle/particleType combination has dominant encounter win rate', () => {
      const phyles = ['philosopher', 'nihilist', 'aesthete', 'builder', 'hedonist', 'scientist', 'mystic'] as const;
      const particleTypes = ['fixer', 'dps', 'tank', 'healer', 'range'] as const;
      const winRates: number[] = [];

      for (const phyle of phyles) {
        for (const particleType of particleTypes) {
          const minor = phyles.find((p) => p !== phyle) ?? 'philosopher';
          const m = createObserver('did:test', 42, phyle, minor, particleType);
          let wins = 0;
          const trials = 200;
          for (let i = 0; i < trials; i++) {
            const { result } = resolveEncounter(m, 5, i);
            if (!result.newFailure) wins++;
          }
          winRates.push(wins / trials);
        }
      }

      // No combination should have win rate > 0.95 or < 0.05
      // (complete dominance or complete weakness)
      for (const rate of winRates) {
        expect(rate).toBeLessThan(0.95);
        expect(rate).toBeGreaterThan(0.05);
      }

      // Win rates should be within reasonable range of each other
      const min = Math.min(...winRates);
      const max = Math.max(...winRates);
      expect(max - min).toBeLessThan(0.3); // No more than 30% spread
    });
  });
});
